import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const g=JSON.parse('{"title":"Charts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/charts.md","filePath":"guide/charts.md","lastUpdated":1772287587000}'),s={name:"guide/charts.md"};function i(n,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="charts" tabindex="-1">Charts <a class="header-anchor" href="#charts" aria-label="Permalink to &quot;Charts&quot;">​</a></h1><p>getbased visualizes every biomarker as a line chart over time. Charts are grouped by category — Biochemistry, Hormones, Lipids, Hematology, and so on — and each category gets its own section on the dashboard.</p><h2 id="reading-a-chart" tabindex="-1">Reading a Chart <a class="header-anchor" href="#reading-a-chart" aria-label="Permalink to &quot;Reading a Chart&quot;">​</a></h2><p>Each line chart shows one marker&#39;s values plotted across your lab dates. The horizontal axis is time; the vertical axis is the marker&#39;s value in your chosen unit (SI or US conventional).</p><p><strong>Reference range band</strong> — A gray shaded region marks the standard reference range. Values inside the band are normal; values outside are colored accordingly.</p><p><strong>Optimal range band</strong> — A green dashed outline shows a tighter optimal range when one is defined. Optimal ranges represent values associated with better long-term outcomes, not just &quot;not abnormal.&quot;</p><p><strong>Data points</strong> — Each dot represents a single lab result. Point color reflects status: green for normal, red for high, blue for low.</p><p><strong>Span gaps</strong> — If a marker has no result on a particular date, the line continues across that gap. You will not see a break in the line just because one date is missing a value.</p><h2 id="chart-layers" tabindex="-1">Chart Layers <a class="header-anchor" href="#chart-layers" aria-label="Permalink to &quot;Chart Layers&quot;">​</a></h2><p>The <strong>Layers</strong> dropdown (visible in the chart area header) lets you overlay additional context on top of every chart:</p><ul><li><strong>Note dots</strong> — Yellow dots appear on the chart at dates where you have written a standalone note. Hover over a dot to see the note text.</li><li><strong>Supplement bars</strong> — Colored bars along the bottom of the chart show when supplements or medications were active.</li><li><strong>Cycle phase bands</strong> — Vertical shading shows your menstrual cycle phases: red (menstrual), blue (follicular), purple (ovulatory), yellow (luteal). A single letter at the top of each band identifies the phase. Available for female profiles with cycle data entered.</li></ul><p>Each layer is toggled independently and your choice is saved per profile. The Layers dropdown is hidden if you have no notes, supplements, or cycle data.</p><h2 id="detail-modal" tabindex="-1">Detail Modal <a class="header-anchor" href="#detail-modal" aria-label="Permalink to &quot;Detail Modal&quot;">​</a></h2><p>Click any chart card to open the detail modal for that marker. The modal shows:</p><ul><li>Full history table with values, reference ranges, and status for each date</li><li>The trend direction and any alerts</li><li>AI interpretation (if an AI provider is configured)</li><li>Your notes associated with that marker&#39;s dates</li></ul><h2 id="single-point-categories" tabindex="-1">Single-Point Categories <a class="header-anchor" href="#single-point-categories" aria-label="Permalink to &quot;Single-Point Categories&quot;">​</a></h2><p>Some categories — Fatty Acids is the main example — contain measurements that are typically taken once rather than tracked over time. These display as a grid of value cards rather than a trend line chart. Each card shows the measured value alongside its reference range.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use the date range filter in the header to zoom into a specific period. All charts update immediately when you change the range.</p></div><h2 id="phenoage-chart" tabindex="-1">PhenoAge Chart <a class="header-anchor" href="#phenoage-chart" aria-label="Permalink to &quot;PhenoAge Chart&quot;">​</a></h2><p>The PhenoAge marker (under the Aging or Biochemistry category) includes a gray dashed line showing your chronological age for comparison. PhenoAge is a biological age estimate calculated from nine standard biomarkers — it requires your date of birth to be set in Settings.</p>',20)])])}const u=a(s,[["render",i]]);export{g as __pageData,u as default};
